import Stripe from 'stripe';
import { OrderService } from './orderService';
import { config } from '../config';

export class WebhookHandler {
  private orderService: OrderService;

  constructor(orderService: OrderService) {
    this.orderService = orderService;
  }

  verifySignature(payload: string | Buffer, signature: string): Stripe.Event {
    const stripe = new Stripe(config.stripeSecretKey);
    return stripe.webhooks.constructEvent(
      payload,
      signature,
      config.stripeWebhookSecret
    );
  }

  handleEvent(event: Stripe.Event): { status: string; orderId?: string } {
    switch (event.type) {
      case 'payment_intent.succeeded': {
        const intent = event.data.object as Stripe.PaymentIntent;
        const order = this.orderService.findByPaymentIntent(intent.id);
        if (order) {
          this.orderService.updateStatus(order.id, 'paid');
          return { status: 'updated', orderId: order.id };
        }
        return { status: 'order_not_found' };
      }
      case 'payment_intent.payment_failed': {
        const intent = event.data.object as Stripe.PaymentIntent;
        const order = this.orderService.findByPaymentIntent(intent.id);
        if (order) {
          this.orderService.updateStatus(order.id, 'failed');
          return { status: 'updated', orderId: order.id };
        }
        return { status: 'order_not_found' };
      }
      default:
        return { status: 'unhandled' };
    }
  }
}

import { Router, Request, Response } from 'express';
import { config } from '../config';
import { WebhookHandler } from '../services/webhookHandler';
import { OrderService } from '../services/orderService';

export function createPaymentRouter(orderService: OrderService): Router {
  const router = Router();
  const webhookHandler = new WebhookHandler(orderService);

  router.post('/create-intent', (req: Request, res: Response) => {
    res.json({ clientSecret: 'mock_secret' });
  });

  router.post('/webhook', (req: Request, res: Response) => {
    const signature = req.headers['stripe-signature'] as string;
    if (!signature) {
      res.status(400).json({ error: 'Missing stripe-signature header' });
      return;
    }

    try {
      const event = webhookHandler.verifySignature(req.body, signature);
      const result = webhookHandler.handleEvent(event);
      res.json(result);
    } catch (err: any) {
      res.status(400).json({ error: `Webhook error: ${err.message}` });
    }
  });

  return router;
}

