import { WebhookHandler } from '../src/services/webhookHandler';

describe('WebhookHandler', () => {
  let orderService: OrderService;
  let handler: WebhookHandler;

  beforeEach(() => {
    orderService = new OrderService();
    handler = new WebhookHandler(orderService);
    orderService.create('ord-1', 5000, 'pi_success');
    orderService.create('ord-2', 3000, 'pi_fail');
  });

  test('handles payment_intent.succeeded', () => {
    const event = {
      type: 'payment_intent.succeeded',
      data: { object: { id: 'pi_success' } },
    } as any;
    const result = handler.handleEvent(event);
    expect(result.status).toBe('updated');
    expect(result.orderId).toBe('ord-1');
    const order = orderService.findByPaymentIntent('pi_success');
    expect(order!.status).toBe('paid');
  });

  test('handles payment_intent.payment_failed', () => {
    const event = {
      type: 'payment_intent.payment_failed',
      data: { object: { id: 'pi_fail' } },
    } as any;
    const result = handler.handleEvent(event);
    expect(result.status).toBe('updated');
    const order = orderService.findByPaymentIntent('pi_fail');
    expect(order!.status).toBe('failed');
  });

  test('returns order_not_found for unknown intent', () => {
    const event = {
      type: 'payment_intent.succeeded',
      data: { object: { id: 'pi_unknown' } },
    } as any;
    expect(handler.handleEvent(event).status).toBe('order_not_found');
  });

  test('returns unhandled for other events', () => {
    const event = { type: 'charge.refunded', data: { object: {} } } as any;
    expect(handler.handleEvent(event).status).toBe('unhandled');
  });
});
